using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Environments;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

var config = DefaultConfig.Instance
    .AddJob(Job.Default.WithRuntime(CoreRuntime.Core90).WithId("NET9"))
    .AddJob(Job.Default.WithRuntime(CoreRuntime.Core100).WithId("NET10"));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config, args);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _smallAnalyzer = null!;
    private TextAnalyzer _largeAnalyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        _smallAnalyzer = new TextAnalyzer("The quick brown fox jumps over the lazy dog near the river bank");

        // ~1000 words
        var rng = new Random(42);
        var words = new string[1000];
        for (int i = 0; i < words.Length; i++)
        {
            int len = rng.Next(2, 12);
            var chars = new char[len];
            for (int j = 0; j < len; j++)
                chars[j] = (char)('a' + rng.Next(26));
            words[i] = new string(chars);
        }
        _largeAnalyzer = new TextAnalyzer(string.Join(' ', words));
    }

    [Benchmark]
    public double AverageWordLength_Small() => _smallAnalyzer.AverageWordLength();

    [Benchmark]
    public double AverageWordLength_Large() => _largeAnalyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram_Small() => _smallAnalyzer.WordLengthHistogram();

    [Benchmark]
    public object WordLengthHistogram_Large() => _largeAnalyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount_Small() => _smallAnalyzer.UniqueWordCount();

    [Benchmark]
    public int UniqueWordCount_Large() => _largeAnalyzer.UniqueWordCount();
}

